const POSTS_PER_PAGE = 5;

const Community: React.FC<CommunityProps> = ({ onAddNotification, blockedUsers, onBlockUser, onSubmitReport, balance, onUpdateBalance }) => {
  const [view, setView] = useState<CommunityView>('vibe');
