  const handleDeletePost = (postId: string) => {
    if (!isAdmin) return;
    if (window.confirm("Admin: Remove this post for good?")) {
      // Note: Real DB would need a delete method, but we filter for now locally
      setVibePosts(prev => prev.filter(p => p.id !== postId));
