              </div>
              <button onClick={() => setShowSafetyModal(false)} className="text-slate-300 p-2"><X size={28} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 pt-6 space-y-8 no-scrollbar">
              {/* Guidelines Section */}
              <div className="space-y-4">
                <p className="text-[10px] font-black text-[#004d3d] uppercase tracking-widest opacity-40">UGC Guidelines</p>
                <div className="space-y-3">
