      location: 'Suncorp Stadium, Brisbane',
      status: 'Purchased',
      type: 'Two Match',
      pricePPS: 4999,
      priceSingle: 6500,
      image: 'https://images.unsplash.com/photo-1541252260730-0412e8e2108e?q=80&w=200&auto=format&fit=crop',
      date: 'Oct 2027'
    },
    {
      id: 'e2',
      title: 'Cape Town Sevens Gold Pass',
      location: 'DHL Stadium, Cape Town',
      status: 'Wishlisted',
      type: 'Two Match',
