                           <span className="text-[8px] font-bold text-slate-300 uppercase">{new Date(report.timestamp).toLocaleDateString()}</span>
                        </div>
                        <p className="text-[10px] font-medium text-slate-600 line-clamp-2 italic mb-2">"{report.postContent}"</p>
                        <div className="flex items-center space-x-1.5 text-[9px] font-black text-red-400 uppercase tracking-widest">
                          <AlertTriangle size={10} />
                          <span>Flagged: {report.reason}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>

            {isAdmin && (
              <div className="p-8 pt-4 bg-slate-50 border-t border-slate-100 shrink-0">
                <button 
                  onClick={() => { setShowSafetyModal(false); onGoToAdmin?.(); native.hapticImpact(); }}
                  className="w-full bg-[#004d3d] text-[#fdb913] py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg flex items-center justify-center space-x-3 active:scale-95 transition-all"
                >
                  <ShieldCheck size={18} />
                  <span>Admin Moderation Tab</span>
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

