                   >
                     <option>High Gees</option>
                     <option>Chill</option>
                     <option>Singing</option>
                     <option>Family</option>
                   </select>
                 </div>
                 <div className="space-y-1">
                   <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Status</label>
                   <select 
                     className="w-full bg-white border border-slate-100 rounded-2xl px-4 py-3.5 text-xs font-bold text-[#004d3d] outline-none shadow-sm"
                     value={partnerForm.status}
                     onChange={e => setPartnerForm({...partnerForm, status: e.target.value as any})}
                   >
                     <option value="active">Active</option>
                     <option value="paused">Paused</option>
                   </select>
                 </div>
               </div>
               <div className="grid grid-cols-2 gap-4">
                 <AdminInput label="Latitude" value={partnerForm.lat?.toString()} onChange={v => setPartnerForm({...partnerForm, lat: parseFloat(v) || 0})} icon={<MapPin size={14} />} type="number" />
                 <AdminInput label="Longitude" value={partnerForm.lng?.toString()} onChange={v => setPartnerForm({...partnerForm, lng: parseFloat(v) || 0})} icon={<MapPin size={14} />} type="number" />
               </div>
               <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Description / Deals</label>
                  <textarea 
                    className="w-full bg-white border border-slate-100 rounded-2xl px-5 py-3.5 text-xs font-bold text-[#004d3d] outline-none shadow-sm min-h-[100px]"
                    value={partnerForm.description}
                    onChange={e => setPartnerForm({...partnerForm, description: e.target.value})}
                    placeholder="Enter special fan deals or venue rules..."
                  />
               </div>
            </div>
            <div className="p-8 bg-white border-t border-slate-100 shrink-0">
               <button onClick={handleSavePartner} className="w-full bg-[#004d3d] text-[#fdb913] py-5 rounded-[32px] font-black uppercase text-sm tracking-[0.2em] shadow-luxury flex items-center justify-center space-x-4 active:scale-95">
                  <Save size={24} /> <span>SAVE PARTNER</span>
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const AdminInput: React.FC<{ label: string, value?: string, onChange: (v: string) => void, icon?: React.ReactNode, type?: string, placeholder?: string }> = ({ label, value, onChange, icon, type = "text", placeholder }) => (
  <div className="space-y-1">
    <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">{label}</label>
    <div className="relative group">
      <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">{icon}</div>
      <input 
        type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder}
        className="w-full bg-white border border-slate-100 rounded-2xl pl-11 pr-4 py-3.5 text-xs font-bold text-[#004d3d] outline-none shadow-sm focus:ring-2 focus:ring-[#fdb913]/20"
      />
    </div>
  </div>
);

const SubNavButton: React.FC<{ icon: React.ReactNode, label: string, active: boolean, onClick: () => void, badge?: number }> = ({ icon, label, active, onClick, badge }) => (
  <button onClick={onClick} className={`px-5 py-2.5 rounded-full flex items-center space-x-2 border transition-all shrink-0 ${active ? 'bg-[#004d3d] text-[#fdb913] border-[#004d3d] shadow-md' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
    {icon}
    <span className="text-[10px] font-black uppercase tracking-widest">{label}</span>
  </button>
);

export default Admin;

import React, { useState, useRef, useMemo } from 'react';
import { 
  Settings, Shield, Award, HelpCircle, LogOut, ChevronRight, Share2, 
  Bell, Camera, Edit3, Check, X, AlertCircle, Compass, Ticket, 
  User, Mail, Phone, Globe, CreditCard, ChevronLeft, Heart, CheckCircle2, ArrowRight, ShieldCheck,
  MapPin, LifeBuoy, MessageSquare, Headphones, FileText, Info, ShieldAlert,
  Flame, Trophy, Zap, TrendingUp, Clock, ShoppingBag, Plus, Minus, BellRing, Languages, Coins, Fingerprint, Star, Gift, ExternalLink,
  Terminal, ShieldX, MessageCircle, Flag, AlertTriangle, CalendarDays, Upload, RefreshCw, Map as MapIcon
