                  <div className="space-y-1">
                    <div className="flex items-center justify-between">
                      <span className={`text-[7px] font-black px-1.5 py-0.5 rounded uppercase tracking-widest ${exp.status === 'Purchased' ? 'bg-[#004d3d] text-[#fdb913]' : 'bg-[#fdb913] text-[#004d3d]'}`}>
                        {exp.status}
                      </span>
                      <span className="text-[8px] font-bold text-slate-400 flex items-center">
                        <CalendarDays size={10} className="mr-1" />
                        {exp.date}
                      </span>
                    </div>
                    <h4 className="text-xs font-black text-[#004d3d] truncate">{exp.title}</h4>
                    <p className="text-[9px] font-medium text-slate-500 truncate flex items-center">
                      <MapPin size={9} className="mr-1 text-[#fdb913]" />
                      {exp.location}
                    </p>
                  </div>
                  <button 
                    onClick={() => { native.hapticImpact(); }}
                    className="mt-2 text-left text-[9px] font-black text-[#004d3d] uppercase tracking-[0.2em] flex items-center hover:opacity-70"
                  >
                    View Details <ArrowRight size={10} className="ml-1" />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {/* Fan Preferences Section */}
      <div className="bg-white rounded-[32px] p-6 shadow-sm border border-slate-100 space-y-6">
        <h3 className="font-black text-lg font-heading text-[#004d3d]">Fan Hub Access</h3>
        <div className="space-y-4">
          <PreferenceItem 
            icon={<ShieldAlert size={18} className="text-red-500" />}
            label="Safety & Compliance"
            desc="UGC Guidelines & Reports"
            action={<button onClick={() => { setShowSafetyModal(true); native.hapticImpact(); }} className="p-2 bg-red-50 text-red-500 rounded-xl active:scale-90 transition-all shadow-sm"><Info size={16} /></button>}
          />
          <PreferenceItem 
            icon={<HelpCircle size={18} className="text-[#004d3d]" />}
            label="Help & Support"
            desc="Elite Fan Concierge"
            action={<ChevronRight size={18} className="text-slate-300" />}
          />
        </div>
      </div>

      {/* Developer Access Toggle (Quick Admin Mode) */}
      <div className="bg-slate-900 rounded-[32px] p-6 shadow-lg border border-slate-800 space-y-4">
        <div className="flex items-center space-x-2 text-[#fdb913]">
          <Terminal size={16} />
          <h3 className="font-black text-[10px] uppercase tracking-[0.2em]">Developer Access</h3>
        </div>
        <div className="flex items-center justify-between">
          <div>
            <p className="text-xs font-bold text-white leading-none mb-1">Toggle Admin Mode</p>
            <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Unlock Command Center</p>
          </div>
          <Toggle checked={isAdmin || false} onChange={() => { onToggleAdmin?.(); native.hapticSuccess(); }} />
        </div>
      </div>

      <button onClick={() => { onLogout?.(); native.hapticImpact(); }} className="w-full px-6 py-4 bg-red-50 text-red-600 rounded-2xl flex items-center justify-center space-x-3 active:scale-95 transition-all border border-red-100">
        <LogOut size={20} /> <span className="font-black text-xs uppercase tracking-[0.2em]">Sign Out</span>
      </button>

      {/* EDIT MODAL */}
      {isEditModalOpen && (
        <div className="fixed inset-0 z-[10000] bg-black/60 backdrop-blur-md flex items-center justify-center p-4 animate-fadeIn">
          <div className="bg-white w-full max-w-sm rounded-[40px] shadow-luxury animate-scaleIn p-8 space-y-6">
             <div className="flex justify-between items-center">
                <h3 className="text-xl font-black font-heading text-[#004d3d]">Update Profile</h3>
                <button onClick={() => setIsEditModalOpen(false)} className="text-slate-300"><X size={24} /></button>
             </div>
             <div className="space-y-4">
               <div>
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-3">Bio / Motto</label>
                  <textarea 
                    value={profileData.bio} 
                    onChange={e => setProfileData({...profileData, bio: e.target.value})}
                    className="w-full bg-slate-50 border-none rounded-2xl px-5 py-3.5 text-xs font-bold text-[#004d3d] outline-none min-h-[100px] focus:ring-2 focus:ring-[#fdb913]/20"
                    placeholder="Tell the hub who you are..."
                  />
               </div>
             </div>
             <button 
               onClick={handleSaveBio}
               className="w-full bg-[#004d3d] text-[#fdb913] py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg active:scale-95 transition-all"
             >
               Save Changes
             </button>
          </div>
        </div>
      )}

      {/* SAFETY & COMPLIANCE MODAL */}
      {showSafetyModal && (
        <div className="fixed inset-0 z-[10000] bg-black/80 backdrop-blur-xl flex items-center justify-center p-4 animate-fadeIn">
          <div className="bg-white w-full max-w-sm rounded-[48px] shadow-luxury animate-scaleIn relative overflow-hidden flex flex-col max-h-[85vh]">
            <div className="p-8 pb-4 flex justify-between items-center shrink-0 border-b border-slate-50">
              <div className="flex items-center space-x-3">
                <div className="p-2 bg-red-50 text-red-500 rounded-xl"><ShieldAlert size={20} /></div>
                <div>
                  <h3 className="text-xl font-black font-heading text-[#004d3d]">Safety & Vibe</h3>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">UGC Compliance</p>
                </div>
              </div>
              <button onClick={() => setShowSafetyModal(false)} className="text-slate-300 p-2"><X size={28} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 pt-6 space-y-8 no-scrollbar">
              {/* Guidelines Section */}
              <div className="space-y-4">
                <p className="text-[10px] font-black text-[#004d3d] uppercase tracking-widest opacity-40">UGC Guidelines</p>
                <div className="space-y-3">
                  {UGC_GUIDELINES.map((g, idx) => (
                    <div key={idx} className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                      <h4 className="text-xs font-black text-[#004d3d] uppercase tracking-tight mb-1">{g.title}</h4>
                      <p className="text-[10px] font-medium text-slate-500 leading-relaxed">{g.desc}</p>
                    </div>
                  ))}
                </div>
              </div>

              {/* Your Reported Content Section */}
              <div className="space-y-4">
                <p className="text-[10px] font-black text-[#004d3d] uppercase tracking-widest opacity-40">Your Reported Content</p>
                {userReports.length === 0 ? (
                  <div className="bg-green-50 p-6 rounded-3xl border border-green-100 flex flex-col items-center text-center">
                    <CheckCircle2 size={32} className="text-green-500 mb-3" />
                    <p className="text-xs font-black text-green-700 uppercase tracking-tight">All Clean, Bru!</p>
                    <p className="text-[9px] font-medium text-green-600 mt-1">None of your posts have been reported by the community.</p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {userReports.map(report => (
                      <div key={report.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
                        <div className="flex justify-between items-start mb-2">
                           <span className={`text-[8px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest ${report.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-400'}`}>
                             {report.status}
                           </span>
                           <span className="text-[8px] font-bold text-slate-300 uppercase">{new Date(report.timestamp).toLocaleDateString()}</span>
                        </div>
                        <p className="text-[10px] font-medium text-slate-600 line-clamp-2 italic mb-2">"{report.postContent}"</p>
                        <div className="flex items-center space-x-1.5 text-[9px] font-black text-red-400 uppercase tracking-widest">
                          <AlertTriangle size={10} />
                          <span>Flagged: {report.reason}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>

            {isAdmin && (
              <div className="p-8 pt-4 bg-slate-50 border-t border-slate-100 shrink-0">
                <button 
                  onClick={() => { setShowSafetyModal(false); onGoToAdmin?.(); native.hapticImpact(); }}
                  className="w-full bg-[#004d3d] text-[#fdb913] py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg flex items-center justify-center space-x-3 active:scale-95 transition-all"
                >
                  <ShieldCheck size={18} />
                  <span>Admin Moderation Tab</span>
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

const PreferenceItem: React.FC<{ icon: React.ReactNode, label: string, desc: string, action: React.ReactNode }> = ({ icon, label, desc, action }) => (
  <div className="flex items-center justify-between">
    <div className="flex items-center space-x-4">
      <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center border border-slate-100">{icon}</div>
      <div>
        <p className="text-sm font-black text-[#004d3d] leading-none mb-1 uppercase tracking-tight">{label}</p>
        <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{desc}</p>
      </div>
    </div>
    {action}
  </div>
);

const Toggle: React.FC<{ checked: boolean, onChange: () => void }> = ({ checked, onChange }) => (
  <button onClick={onChange} className={`w-11 h-6 rounded-full relative transition-all duration-300 ${checked ? 'bg-[#004d3d]' : 'bg-slate-200'}`}>
    <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all duration-300 ${checked ? 'left-6 shadow-sm' : 'left-1'}`} />
  </button>
);

export default Profile;

import React, { useState, useMemo } from 'react';
import { 
  Search, MapPin, CheckCircle2, ArrowRight, X, ShieldCheck, 
  Ticket, Bed, Bus, Flame, Award, SlidersHorizontal,
  Users as UsersIcon, Star, CalendarDays, Clock, Shield, Plus, Minus,
  Copy, Share, FileText, Calendar, QrCode, Download, Share2, Heart,
  Settings, Edit3, Compass
} from 'lucide-react';
import { Experience, AppTab } from '../types';
import { native } from '../services/nativeService';
import { db } from '../services/db';

interface ExperiencesProps {
  experiences: Experience[];
  onAddNotification?: (title: string, message: string, type: 'match' | 'system' | 'wallet') => void;
  onNavigateToTab?: (tab: any) => void;
}

const Experiences: React.FC<ExperiencesProps> = ({ experiences, onAddNotification, onNavigateToTab }) => {
  const [search, setSearch] = useState('');
  const [selectedTier, setSelectedTier] = useState<Experience | null>(null);
  const [isConfirming, setIsConfirming] = useState(false);
  const [bookingType, setBookingType] = useState<'pps' | 'single'>('pps');
  const [quantity, setQuantity] = useState(1);
  const [isSuccess, setIsSuccess] = useState(false);
  const [bookingRef, setBookingRef] = useState('');
  const [wishlist, setWishlist] = useState<string[]>([]);

  const [isFilterDrawerOpen, setIsFilterDrawerOpen] = useState(false);
  const [priceRange, setPriceRange] = useState<number>(150000);

  const currentUser = db.getCurrentUser();
  const isAdmin = currentUser?.role === 'admin';

  const toggleWishlist = (id: string) => {
    native.hapticImpact();
    setWishlist(prev => prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]);
  };

  const getFeatureIcon = (feature: string) => {
    const f = feature.toLowerCase();
    if (f.includes('accommodation') || f.includes('hotel') || f.includes('suite') || f.includes('villa') || f.includes('tent')) return <Bed size={12} />;
    if (f.includes('transport') || f.includes('shuttle') || f.includes('transfer') || f.includes('airport')) return <Bus size={12} />;
    if (f.includes('braai') || f.includes('gala') || f.includes('event') || f.includes('brunch') || f.includes('feast')) return <Flame size={12} />;
    if (f.includes('ticket') || f.includes('entry') || f.includes('pass')) return <Ticket size={12} />;
    if (f.includes('access') || f.includes('vip') || f.includes('gold') || f.includes('deck')) return <Award size={12} />;
    if (f.includes('safari') || f.includes('tour')) return <MapPin size={12} />;
    if (f.includes('meet') || f.includes('legends')) return <UsersIcon size={12} />;
    return <CheckCircle2 size={12} />;
  };

  const parseDate = (dateStr: string) => {
    const parts = dateStr.split(' ');
    if (parts.length < 2) return { day: dateStr, month: 'BOK' };
    return { day: parts[0], month: parts[1].toUpperCase() };
  };

  const filteredTiers = useMemo(() => {
    return experiences.filter(t => {
      const matchesSearch = t.title.toLowerCase().includes(search.toLowerCase()) || 
                            t.location.toLowerCase().includes(search.toLowerCase());
      const matchesPrice = t.pricePPS <= priceRange;
      return matchesSearch && matchesPrice;
    });
  }, [experiences, search, priceRange]);

  const totalPrice = useMemo(() => {
    if (!selectedTier) return 0;
    const basePrice = bookingType === 'pps' ? selectedTier.pricePPS : selectedTier.priceSingle;
    return basePrice * quantity;
  }, [selectedTier, bookingType, quantity]);

  const handleConfirmPurchase = () => {
    const ref = `BOK-${Math.random().toString(36).substring(2, 9).toUpperCase()}`;
    setBookingRef(ref);
    setIsSuccess(true);

    if (currentUser) {
      db.processActivity(currentUser.id, 'purchase');
    }

    native.hapticSuccess();
    if (onAddNotification) {
      onAddNotification("Booking Confirmed", `Lekker! Tour ${ref} is now active in your profile.`, "wallet");
    }
  };

  const resetModals = () => {
    setIsConfirming(false);
    setIsSuccess(false);
    setSelectedTier(null);
    setBookingRef('');
    setQuantity(1);
  };

  return (
    <div className="px-6 space-y-6 animate-fadeIn pt-4 pb-24">
      {/* Search Bar - Refined Style */}
      <div className="flex items-center space-x-3">
        <div className="relative flex-1 group">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-[#004d3d] transition-colors" size={18} />
          <input 
            type="text" 
            placeholder="Search tours or cities..."
            className="w-full bg-white border border-slate-100 rounded-2xl py-3.5 pl-11 pr-4 text-sm font-medium focus:ring-4 focus:ring-[#004d3d]/5 focus:border-[#004d3d]/20 shadow-sm transition-all"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <button 
          onClick={() => setIsFilterDrawerOpen(true)}
          className="w-12 h-12 flex items-center justify-center rounded-2xl bg-white border border-slate-100 text-[#004d3d] shadow-sm active:scale-95 transition-all"
        >
          <SlidersHorizontal size={20} />
        </button>
      </div>

      {/* Results Header */}
      <div className="flex items-center justify-between px-1">
        <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{filteredTiers.length} Experiences Found</p>
        <div className="flex items-center space-x-2">
          <button 
            onClick={() => { native.hapticImpact(); onNavigateToTab?.(AppTab.PROFILE); }}
            className="text-[9px] font-black text-[#004d3d] bg-[#fdb913] px-3 py-1 rounded-full uppercase tracking-widest flex items-center space-x-1.5 shadow-sm active:scale-95 transition-all"
          >
            <Compass size={11} /> <span>My Bookings</span>
          </button>
          {isAdmin && (
            <button 
              onClick={() => onNavigateToTab?.(AppTab.ADMIN)}
              className="text-[9px] font-black text-[#fdb913] bg-[#004d3d] px-3 py-1 rounded-full uppercase tracking-widest flex items-center space-x-1.5 shadow-sm active:scale-95 transition-all"
            >
              <Settings size={11} /> <span>Manage All</span>
            </button>
          )}
        </div>
      </div>

      <div className="space-y-6">
        {filteredTiers.length === 0 ? (
          <div className="py-20 flex flex-col items-center justify-center text-center opacity-40">
            <MapPin size={48} className="mb-4 text-slate-300" />
            <p className="text-xs font-black uppercase tracking-widest">No matching tours, bru.</p>
          </div>
        ) : (
          filteredTiers.map((tier) => {
            const dateInfo = parseDate(tier.startDate);
            const isWishlisted = wishlist.includes(tier.id);
            return (
              <div key={tier.id} className="bg-white rounded-[40px] overflow-hidden shadow-soft border border-slate-100 flex flex-col animate-scaleIn relative group">

                {/* Admin Quick Action */}
                {isAdmin && (
                  <button 
                    onClick={() => { native.hapticImpact(); onNavigateToTab?.(AppTab.ADMIN); }}
                    className="absolute top-4 right-16 w-10 h-10 rounded-full backdrop-blur-md bg-[#fdb913] text-[#004d3d] flex items-center justify-center transition-all z-20 shadow-lg"
                  >
                    <Edit3 size={18} />
                  </button>
                )}

                <div className="h-60 relative bg-slate-200">
                  <img src={tier.image} alt={tier.title} className="w-full h-full object-cover" loading="lazy" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/10 to-transparent"></div>

                  {/* Floating Date Badge */}
                  <div className="absolute top-4 left-4 bg-white/95 backdrop-blur-md rounded-2xl px-3 py-2 flex flex-col items-center shadow-lg min-w-[50px]">
                    <p className="text-[8px] font-black text-[#004d3d] uppercase tracking-widest">{dateInfo.month}</p>
                    <p className="text-lg font-black text-[#004d3d] leading-none">{dateInfo.day}</p>
                  </div>

                  {/* Wishlist Button */}
                  <button 
                    onClick={() => toggleWishlist(tier.id)}
                    className={`absolute top-4 right-4 w-10 h-10 rounded-full backdrop-blur-md flex items-center justify-center transition-all z-10 ${isWishlisted ? 'bg-red-500 text-white' : 'bg-black/20 text-white'}`}
                  >
                    <Heart size={18} fill={isWishlisted ? 'currentColor' : 'none'} />
                  </button>

                  <div className="absolute bottom-4 left-5 flex items-center space-x-2">
                    <div className="bg-[#fdb913] text-[#004d3d] px-2.5 py-1 rounded-lg shadow-md">
                      <span className="text-[9px] font-black uppercase tracking-wider">{tier.type}</span>
                    </div>
                    <div className="bg-white/20 backdrop-blur-md border border-white/30 px-3 py-1 rounded-lg">
                      <span className="text-[9px] font-black text-white uppercase tracking-wider">{tier.location}</span>
                    </div>
                  </div>
                </div>

                <div className="p-6 space-y-4">
                  <div>
                    <h3 className="font-black text-xl font-heading text-[#004d3d] leading-tight tracking-tight mb-1 line-clamp-2 min-h-[2.4rem]">{tier.title}</h3>
                    <div className="flex items-center text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                      <CalendarDays size={12} className="mr-1.5 text-[#fdb913]" />
                      {tier.startDate} — {tier.endDate}
                    </div>
                  </div>

                  <div className="flex flex-wrap gap-2">
                    {tier.features.slice(0, 4).map((feature, idx) => (
                      <div key={idx} className="flex items-center space-x-1.5 bg-slate-50 border border-slate-100 px-3 py-2 rounded-xl">
                        <div className="text-[#fdb913]">{getFeatureIcon(feature)}</div>
                        <span className="text-[9px] font-bold text-slate-500 uppercase tracking-tight whitespace-nowrap">{feature}</span>
                      </div>
                    ))}
                    {tier.features.length > 4 && (
                      <div className="flex items-center justify-center bg-slate-50 border border-slate-100 px-3 py-2 rounded-xl">
                        <span className="text-[9px] font-bold text-slate-300 uppercase">+{tier.features.length - 4}</span>
                      </div>
                    )}
                  </div>

                  <div className="pt-4 border-t border-slate-100 flex items-center justify-between">
                    <div>
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] mb-0.5">Package Starts</p>
                      <div className="flex items-baseline space-x-1">
                        <span className="text-lg font-black text-[#004d3d]">R {tier.pricePPS.toLocaleString()}</span>
                        <span className="text-[8px] font-black text-slate-300 uppercase tracking-widest">PPS</span>
                      </div>
                    </div>
                    <button 
                      onClick={() => { setSelectedTier(tier); setBookingType('pps'); setQuantity(1); setIsConfirming(true); native.hapticImpact(); }}
                      className="h-14 px-6 bg-[#004d3d] text-[#fdb913] rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] shadow-lg flex items-center space-x-3 active:scale-95 transition-all"
                    >
                      <span>Explore</span>
                      <ArrowRight size={16} />
                    </button>
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* Filter Overlay */}
      {isFilterDrawerOpen && (
        <div className="fixed inset-0 z-[9999] bg-black/50 backdrop-blur-md flex items-end sm:items-center justify-center animate-fadeIn">
          <div className="bg-white w-full sm:max-w-sm rounded-t-[40px] sm:rounded-[40px] p-8 animate-slideUp relative shadow-luxury">
            <button onClick={() => setIsFilterDrawerOpen(false)} className="absolute top-6 right-6 text-slate-300 p-2"><X size={24} /></button>
            <h3 className="text-2xl font-black font-heading text-[#004d3d] mb-8">Filter Experiences</h3>

            <div className="space-y-8 pb-8">
              <div className="space-y-4">
                <div className="flex justify-between items-baseline">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Max Budget (R)</p>
                  <p className="text-sm font-black text-[#004d3d]">R {priceRange.toLocaleString()}</p>
                </div>
                <input 
                  type="range" min="5000" max="150000" step="5000"
                  value={priceRange}
                  onChange={(e) => setPriceRange(parseInt(e.target.value))}
                  className="w-full h-2 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-[#004d3d]"
                />
              </div>

              <div className="space-y-4">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Duration</p>
                <div className="flex flex-wrap gap-2">
                  {['Weekends', 'Full Week', 'Finals'].map(opt => (
                    <button key={opt} className="px-4 py-2 rounded-xl border border-slate-100 text-[10px] font-black uppercase text-slate-500 hover:bg-slate-50">
                      {opt}
                    </button>
                  ))}
                </div>
              </div>

              <button onClick={() => { setIsFilterDrawerOpen(false); native.hapticImpact(); }} className="w-full bg-[#004d3d] text-white py-5 rounded-2xl font-black uppercase text-[11px] tracking-widest shadow-xl active:scale-95 transition-all">
                Show {filteredTiers.length} Results
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Purchase Modal */}
      {isConfirming && selectedTier && (
        <div className="fixed inset-0 z-[10000] bg-black/60 backdrop-blur-md flex items-center justify-center p-4 animate-fadeIn">
          <div className="bg-[#f8fafc] w-full max-w-sm rounded-[48px] shadow-luxury animate-scaleIn relative overflow-hidden flex flex-col h-[85vh] border border-white/50">

            <div className="flex-1 overflow-y-auto no-scrollbar">
              {!isSuccess ? (
                <div className="p-8">
                  <div className="flex justify-between items-center mb-8">
                     <h3 className="text-2xl font-black font-heading text-[#004d3d]">Booking Details</h3>
                     <button onClick={resetModals} className="text-slate-300 p-2"><X size={28} /></button>
                  </div>

                  <div className="flex items-center space-x-5 mb-8 bg-white p-5 rounded-[32px] border border-slate-100 shadow-sm">
