        <section className="bg-slate-900 rounded-[40px] p-8 shadow-luxury border border-slate-800 overflow-hidden relative group">
          <div className="absolute top-0 right-0 w-32 h-32 bg-[#fdb913]/5 rounded-full -mr-16 -mt-16 blur-3xl"></div>
          <div className="flex flex-col items-center text-center mb-10">
