import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Home from './pages/Home';
import Experiences from './pages/Experiences';
import Community from './pages/Community';
import Profile from './pages/Profile';
import Wallet from './pages/Wallet';
import Admin from './pages/Admin';
import GreenMile from './pages/GreenMile';
import Landing from './pages/Landing';
import BokBotLive from './components/BokBotLive'; // Note: Kept file name but UI is BOK-CONCIERGE
import { AppTab, AppNotification, Experience, Member, ContentReport, FanZoneHub } from './types';
import { db } from './services/db';
import { authService } from './services/authService';
import { isFirebaseConfigured } from './services/firebase';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [isInitializing, setIsInitializing] = useState(true);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState<Member | null>(null);
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.HOME);

  const [balance, setBalance] = useState<number>(0);
  const [experiences, setExperiences] = useState<Experience[]>([]);
  const [hubs, setHubs] = useState<FanZoneHub[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [reports, setReports] = useState<ContentReport[]>([]);
  const [members, setMembers] = useState<Member[]>([]);

  // Promo Mode State
  const [isPromoMode, setIsPromoMode] = useState(false);
  const [isLiveBotOpen, setIsLiveBotOpen] = useState(false);

  useEffect(() => {
    const initializeAuth = async () => {
      if (!isFirebaseConfigured) {
        const savedUser = db.getCurrentUser();
        if (savedUser) {
          setCurrentUser(savedUser);
          setBalance(savedUser.balance);
          setIsLoggedIn(true);
        }
        setIsInitializing(false);
        return;
      }

      const unsubscribe = authService.onAuthStateChanged(async (firebaseUser) => {
        if (firebaseUser) {
          const member = await db.getMemberById(firebaseUser.uid);
          if (member) {
            setCurrentUser(member);
            db.setCurrentUser(member);
            setBalance(member.balance);
            setIsLoggedIn(true);
          }
        }
        setIsInitializing(false);
      });

      return () => unsubscribe();
    };

    initializeAuth();
  }, []);

  useEffect(() => {
    const loadData = async () => {
      const exps = await db.getExperiences();
      setExperiences(exps);
      const hbList = await db.getHubs();
      setHubs(hbList);
    };
    loadData();
  }, []);

  const addNotification = (title: string, message: string, type: 'match' | 'system' | 'wallet') => {
    const newNotif: AppNotification = {
      id: Date.now().toString(),
      title,
      message,
      time: 'Just now',
      read: false,
      type
    };
    db.addNotification(newNotif);
    setNotifications(prev => [newNotif, ...prev]);
  };

  const handleAuth = async (role: 'admin' | 'member') => {
    if (!isFirebaseConfigured) {
      const guestUser: Member = {
        id: 'guest-fan',
        name: role === 'admin' ? "Bok Admin" : "Thabo Mokoena",
        email: role === 'admin' ? "admin@bokfontein.com" : "thabo@bokfontein.com",
        phone: "+27 82 000 0000",
        status: 'active',
        joinDate: new Date().toISOString(),
        balance: 15200,
        geesLevel: 7,
        geesXP: 3400,
        rank: 142,
        rankTier: 'Springbok',
        avatar: role === 'admin' 
          ? "https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200" 
          : "https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=200",
        role: role,
        blockedUsers: [],
        checkIns: []
      };

      setCurrentUser(guestUser);
      db.setCurrentUser(guestUser);
      setBalance(guestUser.balance);
      setIsLoggedIn(true);
      return;
    }

    const user = await authService.loginWithGoogle();
    if (user) {
      setCurrentUser(user);
      setBalance(user.balance);
      setIsLoggedIn(true);
    }
  };

  const handleLogout = async () => {
    if (isFirebaseConfigured) {
      await authService.logout();
    }
    setIsLoggedIn(false);
    setCurrentUser(null);
    db.setCurrentUser(null);
    setActiveTab(AppTab.HOME);
  };

  const renderContent = () => {
    if (!currentUser) return null;
    switch (activeTab) {
      case AppTab.HOME:
        return <Home 
          onAddNotification={addNotification} 
          userName={currentUser.name} 
          onNavigateToTab={setActiveTab} 
          onOpenLiveBot={() => setIsLiveBotOpen(true)}
        />;
      case AppTab.GREEN_MILE:
        return <GreenMile />;
      case AppTab.EXPERIENCES:
        return <Experiences 
          experiences={experiences} 
          onAddNotification={addNotification} 
          onNavigateToTab={setActiveTab}
        />;
      case AppTab.COMMUNITY:
        return <Community 
          onAddNotification={addNotification} 
          blockedUsers={currentUser.blockedUsers}
          onBlockUser={() => {}}
          onSubmitReport={() => {}}
          balance={currentUser.balance}
          onUpdateBalance={(amt) => {
            db.updateMemberBalance(currentUser.id, amt);
            setBalance(prev => prev + amt);
          }}
        />;
      case AppTab.PROFILE:
        return <Profile 
          currentUser={currentUser}
          onLogout={handleLogout}
          onUpdateBalance={(amt) => {
            db.updateMemberBalance(currentUser.id, amt);
            setBalance(prev => prev + amt);
          }}
          isAdmin={currentUser.role === 'admin'}
          onGoToAdmin={() => setActiveTab(AppTab.ADMIN)}
          onNavigateToExperiences={() => setActiveTab(AppTab.EXPERIENCES)}
          onToggleAdmin={() => {
            const newRole = currentUser.role === 'admin' ? 'member' : 'admin';
            const updated = { ...currentUser, role: newRole as any };
            setCurrentUser(updated);
            db.setCurrentUser(updated);
          }}
          reports={reports}
        />;
      case AppTab.WALLET:
        return <Wallet 
          balance={currentUser.balance} 
          onUpdateBalance={(amt) => {
            db.updateMemberBalance(currentUser.id, amt);
            setBalance(prev => prev + amt);
          }} 
          onAddNotification={addNotification} 
        />;
      case AppTab.ADMIN:
        return <Admin 
          members={members} setMembers={setMembers}
          experiences={experiences} setExperiences={setExperiences}
          hubs={hubs} setHubs={setHubs}
          onAddNotification={addNotification}
          reports={reports} setReports={setReports}
          onStartPromo={() => {}}
        />;
      default:
        return <Home 
          onAddNotification={addNotification} 
          userName={currentUser.name} 
          onOpenLiveBot={() => setIsLiveBotOpen(true)}
        />;
    }
  };

  if (isInitializing) {
    return (
      <div className="h-screen w-full bg-[#004d3d] flex flex-col items-center justify-center space-y-6 animate-fadeIn">
        <div className="relative">
          <div className="w-16 h-16 border-4 border-[#fdb913]/20 rounded-full"></div>
          <div className="absolute top-0 w-16 h-16 border-4 border-[#fdb913] border-t-transparent rounded-full animate-spin"></div>
        </div>
        <div className="text-center">
          <h1 className="text-white font-logo text-xl tracking-[0.4em] mb-1">BOK<span className="text-[#fdb913]">FONTEIN</span></h1>
          <p className="text-[#fdb913]/40 text-[8px] font-black uppercase tracking-[0.6em] animate-pulse">Initializing Fan Hub...</p>
        </div>
      </div>
    );
  }

  if (!isLoggedIn) {
    return <Landing onAuth={handleAuth} />;
  }

  return (
    <>
      <Layout 
        activeTab={activeTab} 
        onTabChange={setActiveTab}
        notifications={notifications}
        onMarkRead={() => {}}
        isAdmin={currentUser?.role === 'admin'}
        userName={currentUser?.name}
        hideUI={isPromoMode}
      >
        {renderContent()}
      </Layout>
      <BokBotLive isOpen={isLiveBotOpen} onClose={() => setIsLiveBotOpen(false)} />
    </>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { 
  ChevronRight, Flame, MapPin, X, Send, Sparkles, Loader2, Trophy, 
  Zap, Activity, Camera, Scan, Mic, MicOff, ExternalLink, Info, AlertCircle,
  BarChart3, ArrowUpRight, TrendingUp, Sun, Moon, Sunrise, Sunset, ChevronLeft, Volume2, Fingerprint, Image as ImageIcon, CheckCircle2,
  RefreshCw, RotateCcw, Headphones, Radio, Calendar, Ticket, Award, ShoppingBag, Clock, Users, Shield, ZapIcon, FlipHorizontal, Download,
  CloudRain, Wind, ThermometerSun, Navigation, Car, Bus, Train, Footprints, Plus
} from 'lucide-react';
import { gemini } from '../services/geminiService';
import { bokSync } from '../services/syncService';
import { db } from '../services/db';
import { native } from '../services/nativeService';
import { MatchState, Member } from '../types';

interface Journey {
  id: string;
  start: string;
  destination: string;
  transport: 'Car' | 'Bus' | 'Train' | 'Walk';
  time: string;
}

interface HomeProps {
  onAddNotification: (title: string, message: string, type: 'match' | 'system' | 'wallet') => void;
  userName?: string;
  onNavigateToTab?: (tab: any) => void;
  onOpenLiveBot?: () => void;
}

type FilterType = 'none' | 'horns' | 'flag' | 'sparkles' | 'facepaint';

const Home: React.FC<HomeProps> = ({ onAddNotification, userName = "Thabo", onNavigateToTab, onOpenLiveBot }) => {
  const [match, setMatch] = useState<MatchState>(bokSync.getMatchState());
  const [currentUser, setCurrentUser] = useState<Member | null>(db.getCurrentUser());
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<string | null>(null);
  const [weather, setWeather] = useState<{ temp: string, condition: string, humid: string } | null>(null);
  const [isBrisbane, setIsBrisbane] = useState(false);

  // Journey State
  const [journeys, setJourneys] = useState<Journey[]>([]);
  const [showJourneyModal, setShowJourneyModal] = useState(false);
  const [newJourney, setNewJourney] = useState<Partial<Journey>>({
    start: '',
    destination: '',
    transport: 'Car'
  });

  // Bok Lens States
  const [showBokLens, setShowBokLens] = useState(false);
  const [activeFilter, setActiveFilter] = useState<FilterType>('none');
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);

  useEffect(() => {
    const unsubscribe = bokSync.subscribe((state) => setMatch(state));

    // Detect Location for Home Content
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((pos) => {
        const { latitude, longitude } = pos.coords;
        const inBrisbane = Math.abs(latitude + 27.46) < 0.5 && Math.abs(longitude - 153.02) < 0.5;
        setIsBrisbane(inBrisbane);
        fetchWeather(latitude, longitude);
      });
    } else {
      fetchWeather(-27.4698, 153.0251); // Fallback to Brisbane
    }

    return () => unsubscribe();
  }, []);

  const fetchWeather = async (lat: number, lng: number) => {
    try {
      const query = `What is the current weather at latitude ${lat}, longitude ${lng} for a sports fan?`;
      const result = await gemini.findNearbyBokSpots(lat, lng, query);
      setWeather({ temp: "22°C", condition: "Lekker Gees", humid: "55%" });
    } catch (e) {
      setWeather({ temp: "22°C", condition: "Lekker", humid: "50%" });
    }
  };

  const handleAddJourney = () => {
    if (!newJourney.start || !newJourney.destination) {
      onAddNotification("Eish!", "Fill in both start and destination, bru!", "system");
      return;
    }
    const journey: Journey = {
      id: Date.now().toString(),
      start: newJourney.start || '',
      destination: newJourney.destination || '',
      transport: newJourney.transport as any || 'Car',
      time: 'TBC'
    };
    setJourneys([journey, ...journeys]);
    setShowJourneyModal(false);
    setNewJourney({ start: '', destination: '', transport: 'Car' });
    native.hapticSuccess();
    onAddNotification("Journey Planned", "Lekker! Your match day travel is sorted.", "system");
  };

  const isAdmin = currentUser?.role === 'admin';

  const startBokLens = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user' }, 
        audio: false 
      });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
      setShowBokLens(true);
      native.hapticImpact();
    } catch (err) {
      console.error("Camera error:", err);
      onAddNotification("Eish!", "We need camera access to see your gees, bru.", "system");
    }
  };

  const closeBokLens = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
    }
    setStream(null);
    setShowBokLens(false);
    setActiveFilter('none');
  };

  const captureGees = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    ctx.translate(canvas.width, 0);
    ctx.scale(-1, 1);
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    applyCanvasFilter(ctx, canvas.width, canvas.height);

    const base64 = canvas.toDataURL('image/jpeg').split(',')[1];
    closeBokLens();
    setIsAnalyzing(true);
    native.hapticSuccess();

    try {
      const result = await gemini.analyzeImage(base64);
      setAnalysisResult(result);
      if (currentUser) {
        db.processActivity(currentUser.id, 'post');
        onAddNotification("Lekker Gees!", "Aweh! Your gees analysis earned you +50 XP, my bru.", "system");
      }
    } catch (err) {
      onAddNotification("Eish!", "BOK-CONCIERGE is a bit confused. Try another snap!", "system");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const applyCanvasFilter = (ctx: CanvasRenderingContext2D, w: number, h: number) => {
    if (activeFilter === 'horns') {
      ctx.fillStyle = '#fdb913';
      ctx.beginPath();
      ctx.moveTo(w * 0.3, h * 0.3);
      ctx.quadraticCurveTo(w * 0.2, h * 0.1, w * 0.1, h * 0.2);
      ctx.lineTo(w * 0.25, h * 0.35);
      ctx.fill();
      ctx.beginPath();
      ctx.moveTo(w * 0.7, h * 0.3);
      ctx.quadraticCurveTo(w * 0.8, h * 0.1, w * 0.9, h * 0.2);
      ctx.lineTo(w * 0.75, h * 0.35);
      ctx.fill();
    } else if (activeFilter === 'flag') {
      ctx.globalAlpha = 0.3;
      ctx.fillStyle = 'red'; ctx.fillRect(0, 0, w, h/3);
      ctx.fillStyle = 'blue'; ctx.fillRect(0, (h/3)*2, w, h/3);
      ctx.fillStyle = 'green';
      ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(w/2, h/2); ctx.lineTo(0, h); ctx.fill();
      ctx.globalAlpha = 1.0;
    } else if (activeFilter === 'sparkles') {
      for(let i=0; i<30; i++) {
        ctx.fillStyle = Math.random() > 0.5 ? '#fdb913' : '#004d3d';
        ctx.beginPath();
        ctx.arc(Math.random()*w, Math.random()*h, Math.random()*5, 0, Math.PI*2);
        ctx.fill();
      }
    }
  };

  const getTransportIcon = (mode: string) => {
    switch (mode) {
      case 'Car': return <Car size={16} />;
      case 'Bus': return <Bus size={16} />;
      case 'Train': return <Train size={16} />;
      case 'Walk': return <Footprints size={16} />;
      default: return <Navigation size={16} />;
    }
  };

  return (
    <div className="flex flex-col h-full animate-fadeIn px-6 pb-24 space-y-6 relative overflow-y-auto no-scrollbar">
      {/* Dynamic Header */}
      <div className="pt-2 animate-slideUp relative z-10 flex justify-between items-start shrink-0">
        <div>
          <div className="flex items-center space-x-2 mb-1">
            <div className={`px-2 py-0.5 rounded-md text-[8px] font-black uppercase tracking-widest animate-pulse ${isAdmin ? 'bg-[#004d3d] text-[#fdb913]' : isBrisbane ? 'bg-red-500 text-white' : 'bg-[#fdb913] text-[#004d3d]'}`}>
              {isAdmin ? 'System: Active' : isBrisbane ? 'Brisbane: Event Live' : 'Global Hub Active'}
            </div>
            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-[#004d3d]">
              {isAdmin ? 'Operations Center' : isBrisbane ? 'Brisbane RWC 2027' : 'BOKFONTEIN Global'}
            </span>
          </div>
          <h2 className="text-4xl font-logo text-[#004d3d] tracking-tighter leading-none">
            {isAdmin ? 'AWEH' : 'HOWZIT'}, <span className="text-[#fdb913]">{isAdmin ? 'ADMIN' : userName.split(' ')[0]}!</span> 🇿🇦
          </h2>
        </div>

        {/* Weather Widget */}
        {weather && (
          <div className="bg-white/40 backdrop-blur-md rounded-2xl p-3 border border-white/50 shadow-sm text-right flex flex-col items-end">
             <div className="flex items-center space-x-1.5 text-[#004d3d]">
                <ThermometerSun size={14} className="text-[#fdb913]" />
                <span className="text-xs font-black">{weather.temp}</span>
             </div>
             <p className="text-[7px] font-black text-slate-400 uppercase tracking-widest mt-0.5">{weather.condition}</p>
          </div>
        )}
      </div>

      {isAdmin ? (
        /* ADMIN DASHBOARD VIEW */
        <section className="bg-slate-900 rounded-[40px] p-8 shadow-luxury border border-slate-800 overflow-hidden relative group">
          <div className="absolute top-0 right-0 w-32 h-32 bg-[#fdb913]/5 rounded-full -mr-16 -mt-16 blur-3xl"></div>
          <div className="flex flex-col items-center text-center mb-10">
            <div className="p-4 bg-white/5 rounded-[28px] text-[#fdb913] mb-4 shadow-inner border border-white/5">
              <Activity size={32} />
            </div>
            <div>
              <p className="text-[10px] font-black text-[#fdb913] uppercase tracking-[0.3em] mb-1">Global Status</p>
              <h3 className="text-2xl font-black text-white font-heading tracking-tight">System Operations</h3>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 mb-10">
            <div className="bg-white/5 p-5 rounded-3xl border border-white/10 text-center flex flex-col items-center justify-center">
              <p className="text-[9px] font-black text-white/40 uppercase tracking-widest mb-1.5">Total Saffas</p>
              <p className="text-2xl font-black text-white font-heading">12,402</p>
            </div>
            <div className="bg-white/5 p-5 rounded-3xl border border-white/10 text-center flex flex-col items-center justify-center">
              <p className="text-[9px] font-black text-white/40 uppercase tracking-widest mb-1.5">Avg Gees</p>
              <p className="text-2xl font-black text-[#fdb913] font-heading">8.4<span className="text-[10px] opacity-40 ml-1">/10</span></p>
            </div>
          </div>
          <button 
