const GreenMile: React.FC = () => {
  const [selectedHub, setSelectedHub] = useState<FanZoneHub | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [gamePlan, setGamePlan] = useState<string | null>(null);
  const [userCoords, setUserCoords] = useState<{ lat: number, lng: number } | null>(null);
  const [isLoadingLocation, setIsLoadingLocation] = useState(true);
  const [hubs, setHubs] = useState<FanZoneHub[]>([]);

  useEffect(() => {
    loadData();
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          setUserCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude });
          setIsLoadingLocation(false);
          native.hapticSuccess();
        },
        (err) => {
          console.error("Location error:", err);
          // Fallback to a default center if location is denied
          setUserCoords({ lat: -27.4698, lng: 153.0251 });
          setIsLoadingLocation(false);
        }
      );
    } else {
      setUserCoords({ lat: -27.4698, lng: 153.0251 });
      setIsLoadingLocation(false);
    }
  }, []);

  const loadData = async () => {
    const data = await db.getHubs();
    setHubs(data.filter(h => h.status !== 'paused'));
  };

  const handleGeneratePlan = async () => {
    setIsGeneratingPlan(true);
    native.hapticImpact();

    const lat = userCoords?.lat || -27.4698;
    const lng = userCoords?.lng || 153.0251;

    const prompt = `Generate a Springbok fan game plan for my current area. Include where to watch, what to eat, and where to find the best gees. My coordinates are ${lat}, ${lng}.`;

    try {
      const result = await gemini.findNearbyBokSpots(lat, lng, prompt);
      setGamePlan(result.text || "Eish bru, I couldn't find a spot right now. Keep an eye on the pulse!");
      setIsGeneratingPlan(false);
      native.hapticSuccess();
    } catch (e) {
      setIsGeneratingPlan(false);
    }
  };

  // Logic to project lat/lng to screen coordinates for the stylized radar
  const markers = useMemo(() => {
    if (!userCoords || hubs.length === 0) return [];

    return hubs.map(hub => {
      // Very simple projection relative to user position for the "Radar" look
      // We bound it within a 0-100% range for absolute positioning
      const dLat = (hub.lat - userCoords.lat) * 2000; // Multiplier to spread them out
      const dLng = (hub.lng - userCoords.lng) * 2000;

      const top = 50 - dLat;
      const left = 50 + dLng;

      return {
        ...hub,
        pos: { 
          top: Math.max(10, Math.min(90, top)), 
          left: Math.max(10, Math.min(90, left)) 
        }
      };
    });
  }, [userCoords, hubs]);

  if (isLoadingLocation) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-4 animate-fadeIn">
        <RefreshCw size={40} className="text-[#004d3d] animate-spin" />
        <p className="text-[10px] font-black uppercase tracking-[0.4em] text-[#004d3d]">Scanning Area for Gees...</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full animate-fadeIn bg-slate-50 relative overflow-hidden">
      {/* Stylized Greyscale Map Radar */}
      <div className="flex-1 relative bg-slate-900 overflow-hidden">
        {/* Radar concentric circles */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <div className="w-[80vw] h-[80vw] border border-white/5 rounded-full"></div>
          <div className="w-[60vw] h-[60vw] border border-white/10 rounded-full"></div>
          <div className="w-[40vw] h-[40vw] border border-white/20 rounded-full"></div>
          <div className="w-[20vw] h-[20vw] border border-[#fdb913]/20 rounded-full"></div>
        </div>

        {/* User Marker (Center) */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-20">
          <div className="w-10 h-10 bg-[#004d3d] rounded-full border-4 border-white flex items-center justify-center shadow-2xl relative">
             <Locate size={16} className="text-[#fdb913]" />
             <div className="absolute inset-0 bg-[#004d3d] rounded-full animate-ping opacity-30"></div>
          </div>
        </div>

        {/* stylized background texture - Greyscale Map look */}
        <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1524661135-423995f22d0b?q=80&w=1200')] bg-cover opacity-20 grayscale pointer-events-none"></div>
        <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-slate-900/50 pointer-events-none"></div>

        {/* Dynamic Markers */}
        {markers.map(marker => (
          <button 
            key={marker.id}
            onClick={() => { setSelectedHub(marker); native.hapticImpact(); }}
            className="absolute transition-transform active:scale-90 z-10"
            style={{ 
              top: `${marker.pos.top}%`, 
              left: `${marker.pos.left}%` 
            }}
          >
            <div className="relative group flex items-center justify-center">
